class Solution:
    def countInterestingSubarrays(self, nums, modulo, k):
        n = len(nums)
        total = 0
        for l in range(n):
            cnt = 0
            for r in range(l, n):
                if nums[r] % modulo == k:
                    cnt += 1
                if cnt % modulo == k:
                    total += 1
        return total

