var countInterestingSubarrays = function(nums, modulo, k) {
    const cnt = new Map();
    cnt.set(0, 1);
    let prefixMod = 0;
    let total = 0;
    for (const x of nums) {
        const b = (x % modulo === k) ? 1 : 0;
        prefixMod = (prefixMod + b) % modulo;
        const need = ((prefixMod - k) % modulo + modulo) % modulo;
        total += cnt.get(need) || 0;
        cnt.set(prefixMod, (cnt.get(prefixMod) || 0) + 1);
    }
    return total;
};
